import numpy as np

def mini_batch_loader(X: np.ndarray, y: np.ndarray, batch_size: int, shuffle: bool = True):
    n = X.shape[0]
    indices = np.arange(n)
    if shuffle:
        np.random.shuffle(indices)
    for start in range(0, n, batch_size):
        batch_idx = indices[start:start + batch_size]
        yield X[batch_idx], y[batch_idx]
